select orders.*, user.name as userName from orders left join user on orders.user_id = user.id
and orders.order_no like concat('%', #{orderNo}, '%') and orders.user_id = #{userId}
order by orders.id desc

select orders.*, user.name as userName from orders left join user on orders.user_id = user.id
and orders.order_no like concat('%', #{query.orderNo}, '%') and orders.user_id = #{query.userId}
order by orders.id desc

select orders.*, user.name as userName from orders
left join user on orders.user_id = user.id
where orders.id = #{id}
